def generate_signals(df, params):
    import pandas as pd
    import numpy as np
    length = params['length']
    std = params['std']
    exit_at_middle = params['exit_at_middle']
    df['sma'] = df['close'].rolling(window=length).mean()
    df['stddev'] = df['close'].rolling(window=length).std()
    df['upper'] = df['sma'] + std * df['stddev']
    df['lower'] = df['sma'] - std * df['stddev']
    signals = [0] * len(df)
    position = 0
    for i in range(length, len(df)):
        if position == 0:
            if df['close'].iloc[i] > df['upper'].iloc[i]:
                position = -1
            elif df['close'].iloc[i] < df['lower'].iloc[i]:
                position = 1
        else:
            if exit_at_middle:
                if position == 1 and df['close'].iloc[i] >= df['sma'].iloc[i]:
                    position = 0
                elif position == -1 and df['close'].iloc[i] <= df['sma'].iloc[i]:
                    position = 0
            else:
                if position == 1 and df['close'].iloc[i] >= df['lower'].iloc[i]:
                    position = 0
                elif position == -1 and df['close'].iloc[i] <= df['upper'].iloc[i]:
                    position = 0
        signals[i] = position
    return pd.Series(signals, index=df.index)
